#include<bits/stdc++.h>
using namespace std;
int main(){
	int a[1005],b[1005],n,t,f=0;
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[i]; 
	}
	for(int i=0;i<n-1;i++){
		if(a[i]>a[i+1]){
			t=a[i]-a[i+1];
		}
		else t=a[i+1]-a[i];
			if(t<=n)	b[t]=1;
	}
	for(int i=1;i<=n-1;i++){
		if(b[i]==0){
			f=1;
		}
	}
	if(f) cout<<"Not jolly";
	else cout<<"Jolly";
	return 0;
}
